const { validateCategoryConfiguration } = require('./packages/classification-engine/dist/config/category-config-schema.js');
const config = require('./config/email-categorizer-config.json');
try {
  const validated = validateCategoryConfiguration(config);
  const params = validated.processingConfig.settings.ruleScoring.tuningParameters;
  console.log('✅ Configuration validated successfully!');
  console.log('Tuning Parameters:');
  console.log('  KHigh:', params.KHigh);
  console.log('  KMedium:', params.KMedium);
  console.log('  KLow:', params.KLow);
  console.log('  M_medium:', params.M_medium);
  console.log('  M_low:', params.M_low);
  console.log('  TAIL_DAMPEN:', params.TAIL_DAMPEN);
  console.log('  TAIL_RATIO_CAP:', params.TAIL_RATIO_CAP);
  console.log('  aggregationCap:', params.aggregationCap);
} catch (error) {
  console.error('❌ Validation failed:', error.message);
  process.exit(1);
}
"

